const SEARCH_INDEX = [{"title": "Beast Master", "cat": "Class", "url": "class/beast-master/", "text": "Beast Master Class Guide Beast Master Tier C"}, {"title": "Berserker", "cat": "Class", "url": "class/berserker/", "text": "Berserker Class Guide Berserker Tier C"}, {"title": "Cardinal", "cat": "Class", "url": "class/cardinal/", "text": "Cardinal Class Guide Cardinal Tier B"}, {"title": "Corruptor", "cat": "Class", "url": "class/corruptor/", "text": "Corruptor Class Guide Corruptor Tier D"}, {"title": "Deadeye", "cat": "Class", "url": "class/deadeye/", "text": "Deadeye Class Guide Deadeye Tier D"}, {"title": "Magus", "cat": "Class", "url": "class/magus/", "text": "Magus Class Guide Magus Tier B"}, {"title": "Marksman", "cat": "Class", "url": "class/marksman/", "text": "Marksman Class Guide Marksman Tier D"}, {"title": "Master Breeder", "cat": "Class", "url": "class/master-breeder/", "text": "Master Breeder Class Guide Master Breeder Tier A"}, {"title": "Mercenary", "cat": "Class", "url": "class/mercenary/", "text": "Mercenary Class Guide Mercenary Tier D"}, {"title": "Oracle", "cat": "Class", "url": "class/oracle/", "text": "Oracle Class Guide Oracle Tier D"}, {"title": "Overlord", "cat": "Class", "url": "class/overlord/", "text": "Overlord Class Guide Overlord Tier A"}, {"title": "Slayer", "cat": "Class", "url": "class/slayer/", "text": "Slayer Class Guide Slayer Tier D"}, {"title": "Templar", "cat": "Class", "url": "class/templar/", "text": "Templar Class Guide Templar Tier B"}, {"title": "Void Mage", "cat": "Class", "url": "class/void-mage/", "text": "Void Mage Class Guide Void Mage Tier S"}, {"title": "War Kahuna", "cat": "Class", "url": "class/war-kahuna/", "text": "War Kahuna Class Guide War Kahuna Tier C"}, {"title": "175 and Beyond", "cat": "Guide", "url": "guide/175-and-beyond/", "text": "175 and beyond - Rappelz Codex 175 and Beyond Level 175 - 180: Devildom (DD) Devildom is the primary farming dungeon for this level range. Enter via the Kaia chain quest. Difficulty Experience Notes DD2 1 hour SS = 20% exp You should be able to solo this easily with previous setup. DD3 Much faster exp Possible for most classes - easier for some than others. Class-dependent difficulty. DD4 Highest difficulty Completely different scale. Don't get demotivated if you can't clear yet. Key Drops: Crystals for gear upgrades and DD accessories (8 types that you must collect same as you did for Circus Accessories: Spirit, Undead, Mecca, Beasts, Ains, Dragons, Devils, Antique) Priority: Daily DD runs | Rupee farming | Acquire PW gear for your main class | Upgrade skill cards to +6/+7 Gear Target: At"}, {"title": "Beyond Master Class", "cat": "Guide", "url": "guide/beyond-master-class/", "text": "Beyond Master Class Beyond Master Class Level progression from 153 to 175 with optimized gear and farming strategies. Level 153–160: Early Endgame Choose one of the following methods based on your class strength and gear: Method Location Difficulty Description Method 1 UG Quests Easy Take from village teleport NPCs. Pop Stamina Saver and Growth potions. Spam UG 2 Palmir until level 160. Method 2 Snow Basin Medium Kill dragons until level 160. Best for Void Mage or Berserker (AoE abilities make it easier to kite). Method 3 Labyrinth Dungeon Medium Do quests to final boss summoning Butkada and Akshas. Take quest kill boss abandon. +5% exp per run. Method 4 Island of Gods Hard & Fast Buy Boarding Pass from Black Marketer. 30-min solo to level 160. Not recommended for new players - alts only. "}, {"title": "Boss Card Collection", "cat": "Guide", "url": "guide/boss-card-collection/", "text": "Boss Card Collection Boss Card Collection This is something new players ignore while it has as high impact as a weapon +20 or even more. Easy to get boss cards from Flea. Boss Cards Overview Boss Card Qty Bonuses Obsidicar x7 +200 M.ATK MicroRaptor x5 +150 P.ATK, +150 M.ATK Mephisto x5 +10 Crit Power, +2% Crit Rate Lilith x5 +200 P.ATK, +200 M.ATK Ent x3 +150 P.ATK Yushiva x3 +5000 HP, +5000 MP Devil Slaughter x3 +200 P.ATK, +200 M.ATK Stone Gargoyle x3 +200 P.ATK, +200 M.ATK Devil Reviac x3 +30 Crit Power, +300 P.ATK, +300 M.ATK Dark Alchemist Saragon x3 +10% Crit Rate, +450 P.ATK, +450 M.ATK Bloodthirsty Beast Karmos x3 +50 VIT, +2000 Max HP Shadow of Reaper Necro x3 +50 STR, +50 INT Final Combined Stats Stat Value Physical Attack +1650 P.ATK Magic Attack +1700 M.ATK Critical Rate +12% C"}, {"title": "General Tips & Tricks", "cat": "Guide", "url": "guide/general-tips/", "text": "General Tips and Tricks General Tips & Tricks Essential advice for efficient leveling, gear progression, and gameplay optimization. Strategic Leveling Tips Tip Key Point Survivability over Damage Most players rush for damage but then complain about dying. Prioritize survivability while gearing up at low levels. A Soul of Lunacy card is one of the cheapest and best choices for most classes without healing skills. Vulc Questline Timing Start the daily Vulc questline early. Koala spawns can be unpredictable, and you need the Koala quest to unlock 190+ Vulc content and get free +1 upgrade cubes. Keep R2+20 Helmet Hold onto your R2+20 helmet and keep gear in Distorted (160) until you can afford a +20 Medusa/Nusy helmet. The +1 all skills bonus is worth more than the set bonus. Farm at RoA Until"}, {"title": "Getting Started in Rappelz", "cat": "Guide", "url": "guide/getting-started/", "text": "Getting Started in Rappelz Getting Started in Rappelz Everything a new player needs: early leveling zones, buffs, quests and more. Starting Your Character If you have 0 Rupies on your account, follow these steps first. Note: It's recommended that you walk through the quests of Trainee Island to get a feel of the game the first time if you don't want to skip the initial steps outlined below. Initial Setup Teleport to Hidden Village and go to the merchant then sell everything in your bag. This will get you more than 7,000 Rupees needed for buffs and traveling to Moonlight Dungeon. Put Rupies in Warehouse and delete your character, then create a new one. Go to the Buffer NPC and take the free buff and the 7,000 Rupee Buff. Leveling Phases Level Range Location / Method Notes 1–10 Moonlight Dun"}, {"title": "Pet Taming", "cat": "Guide", "url": "guide/pet-taming/", "text": "Pet Taming Pet Taming -"}, {"title": "Rupee Farming", "cat": "Guide", "url": "guide/rupee-farming/", "text": "Rupee Farming Rupee Farming -"}, {"title": "Lake Kaia", "cat": "Map", "url": "map/lake-kaia/", "text": "Lake Kaia Zone Guide Lake Kaia"}, {"title": "Pig's Spot", "cat": "Map", "url": "map/pigs-spot/", "text": "Pig's Spot Zone Guide Pig's Spot"}, {"title": "Remains of the Ancients", "cat": "Map", "url": "map/remains-of-the-ancients/", "text": "Remains of the Ancients Remains of the Ancients"}, {"title": "SnowBasin", "cat": "Map", "url": "map/snowbasin/", "text": "SnowBasin Zone Guide SnowBasin"}, {"title": "Gnoll Buff Strategy", "cat": "Strategy", "url": "strategy/gnoll-buff/", "text": "Gnoll Buff Strategy Gnoll Buff Strategy"}, {"title": "Legendary Gear Strategy", "cat": "Strategy", "url": "strategy/legendary-gear/", "text": "Legendary Gear Strategy Legendary Gear Strategy"}];